import React from "react";

export default function AboutSection() {
  return (
    <Grid.Container gap={2} justify="center">
      <Grid xs={12} sm={6}>
        <Row justify="center" align="center" css={{ mt: "100px" }}></Row>
        <img src="" alt="" />
      </Grid>
      <Grid xs={12} sm={6}>
        <p>Info cARD area</p>
      </Grid>
    </Grid.Container>
  );
}
